// Filtrar solo mensajes válidos de WhatsApp (texto, ubicación o audio)
const data = $input.first().json;
if (!data.contacts || !data.contacts[0]?.wa_id || !data.messages || data.messages.length === 0) {
    return [];
}
const msg = data.messages[0];
const type = msg?.type;
// Aceptar mensajes de texto (mínimo 3 caracteres, máximo 1000)
if (type === 'text' && msg.text?.body) {
    const body = msg.text.body.trim();
    if (body.length < 3) return []; // demasiado corto — ignorar silenciosamente
    data.messages[0].text.body = body.substring(0, 1000);
    return [{ json: data }];
}
// Aceptar mensajes de ubicación — convertir a texto para el AI Agent
if (type === 'location' && msg.location) {
    const lat = msg.location.latitude;
    const lng = msg.location.longitude;
    data.messages[0].text = { body: `Mi ubicación es: latitud ${lat}, longitud ${lng}` };
    return [{ json: data }];
}
// Aceptar mensajes de audio — se transcribirán en nodos siguientes
if (type === 'audio' && msg.audio?.id) {
    return [{ json: data }];
}
// Otro tipo de mensaje (imagen, sticker, etc.) — ignorar
return [];

// Prepara inputText para el AI Agent
// Para texto/ubicación: lee de Code in JavaScript
// Para audio: lee .transcription devuelto por sub-workflow STT
const msgType = $('Code in JavaScript').item.json.messages[0].type;
if (msgType === 'audio') {
  const transcription = $json.transcription || '';
  if (!transcription) return []; // sub-workflow ya envió el aviso al paciente
  return [{ json: { inputText: `[Nota de voz]: ${transcription}` } }];
}
return [{ json: { inputText: $('Code in JavaScript').item.json.messages[0].text.body } }];

// Prepara el payload para el sub-workflow STT
return [{ json: {
  audioId: $('Code in JavaScript').item.json.messages[0].audio.id,
  wa_id: $('WA Trigger').item.json.contacts[0].wa_id
} }];

const inputText = $('Set Input Text').item.json.inputText;
const formatted = $('Execute: State Reader').item.json.bookingStateFormatted || '';
return [{ json: { inputText, bookingStateFormatted: formatted } }];

